powershell -NoProfile -ExecutionPolicy Bypass -Command "Write-Host '=== ПОЛНАЯ ОЧИСТКА СИСТЕМЫ ===' -ForegroundColor Red; $paths = @('C:\Windows\Prefetch\*','C:\Windows\Temp\*','C:\Windows\Logs\*','C:\Windows\Debug\*','C:\Windows\System32\LogFiles\*','C:\Windows\System32\winevt\Logs\*','C:\Windows\System32\config\systemprofile\AppData\Local\Microsoft\Windows\WER\*','C:\ProgramData\Microsoft\Windows\WER\*','C:\Users\*\AppData\Local\Temp\*','C:\Users\*\AppData\Local\Microsoft\Windows\Explorer\thumbcache_*.db','C:\Users\*\AppData\Local\Microsoft\Windows\INetCache\*','C:\Users\*\AppData\Local\Microsoft\Windows\History\*','C:\Users\*\AppData\Local\Microsoft\Windows\Burn\Burn\*','C:\Users\*\AppData\Local\Microsoft\Windows\Caches\*','C:\Users\*\AppData\Roaming\Microsoft\Windows\Recent\*','C:\Users\*\AppData\Roaming\Microsoft\Windows\PowerShell\PSReadLine\*','C:\Windows\ServiceProfiles\*\AppData\Local\Temp\*'); foreach ($p in $paths) { if (Test-Path $p) { Remove-Item -Path $p -Recurse -Force -ErrorAction SilentlyContinue; Write-Host \"Удалено: $p\" -ForegroundColor Yellow } }; Write-Host '=== ОЧИСТКА EVENT LOGS ===' -ForegroundColor Red; wevtutil.exe el | ForEach-Object { wevtutil.exe cl $_ -ErrorAction SilentlyContinue }; Write-Host '=== ОЧИСТКА DNS ===' -ForegroundColor Red; ipconfig /flushdns | Out-Null; Write-Host '=== ОЧИСТКА RECYCLE BIN ===' -ForegroundColor Red; Clear-RecycleBin -Force -ErrorAction SilentlyContinue; Write-Host '=== ОЧИСТКА WINDOWS UPDATE CACHE ===' -ForegroundColor Red; Stop-Service wuauserv -Force -ErrorAction SilentlyContinue; Remove-Item 'C:\Windows\SoftwareDistribution\Download\*' -Recurse -Force -ErrorAction SilentlyContinue; Start-Service wuauserv -ErrorAction SilentlyContinue; Write-Host '=== ОЧИСТКА BROWSER CACHE ===' -ForegroundColor Red; @('Chrome','Edge','Opera','Brave') | ForEach-Object { $cachePaths = @(\"$env:LOCALAPPDATA\Google\Chrome\User Data\Default\Cache\*\",\"$env:LOCALAPPDATA\Microsoft\Edge\User Data\Default\Cache\*\",\"$env:LOCALAPPDATA\Opera Software\Opera Stable\Cache\*\",\"$env:LOCALAPPDATA\BraveSoftware\Brave-Browser\User Data\Default\Cache\*\"); foreach ($cp in $cachePaths) { if (Test-Path $cp) { Remove-Item -Path $cp -Recurse -Force -ErrorAction SilentlyContinue } } }; Write-Host '=== ОЧИСТКА MEMORY DUMPS ===' -ForegroundColor Red; Remove-Item 'C:\Windows\Minidump\*' -Force -ErrorAction SilentlyContinue; Remove-Item 'C:\Windows\MEMORY.DMP' -Force -ErrorAction SilentlyContinue; Write-Host '=== ОЧИСТКА LOG FILES ===' -ForegroundColor Red; Remove-Item 'C:\Windows\System32\LogFiles\*' -Recurse -Force -ErrorAction SilentlyContinue; Write-Host 'ГОТОВО! ВСЕ ОЧИЩЕНО!' -ForegroundColor Green"
